const express = require('express');
const bodyParser = require('body-parser');
const twilio = require('twilio');
const crypto = require('crypto');

const app = express();
app.use(bodyParser.json());

// Twilio configuration
const accountSid = 'your_account_sid';
const authToken = 'your_auth_token';
const client = new twilio(accountSid, authToken);

// In-memory storage for verification codes and session data
const sessions = {};

// Generate a random 6-digit code
function generateCode() {
    return Math.floor(100000 + Math.random() * 900000).toString();
}

// Send SMS with the verification code
async function sendVerificationCode(phoneNumber, code) {
    try {
        await client.messages.create({
            body: `Your verification code is ${code}`,
            from: 'your_twilio_phone_number',
            to: phoneNumber
        });
        console.log(`SMS sent to ${phoneNumber}`);
    } catch (error) {
        console.error('Error sending SMS:', error);
    }
}

// Route to initiate the authentication process
app.post('/start-auth', async (req, res) => {
    const { phoneNumber } = req.body;

    if (!phoneNumber) {
        return res.status(400).json({ error: 'Phone number is required' });
    }

    const code = generateCode();
    sessions[phoneNumber] = { code, timestamp: Date.now() };

    await sendVerificationCode(phoneNumber, code);

    res.json({ message: 'Verification code sent' });
});

// Route to verify the user input
app.post('/verify-code', (req, res) => {
    const { phoneNumber, userInput } = req.body;

    if (!phoneNumber || !userInput) {
        return res.status(400).json({ error: 'Phone number and user input are required' });
    }

    if (!sessions[phoneNumber]) {
        return res.status(401).json({ error: 'No verification code found for this phone number' });
    }

    const { code, timestamp } = sessions[phoneNumber];
    const currentTime = Date.now();
    const timeDiff = (currentTime - timestamp) / 60000; // Time difference in minutes

    if (code !== userInput || timeDiff > 5) {
        return res.status(401).json({ error: 'Invalid verification code or expired' });
    }

    delete sessions[phoneNumber]; // Remove the session data after successful verification
    res.json({ message: 'Verification successful' });
});

const PORT = process.env.PORT || 3000;
app.listen(PORT, () => {
    console.log(`Server is running on port ${PORT}`);
});